.planner__body {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(300px, 20rem);
  gap: 1rem;
  align-items: start;
  position: relative;
}

.planner__sidebar-pane {
  position: sticky;
  top: var(--today-sticky-offset);
  align-self: start;
  min-width: 0;
  z-index: 8;
}

.planner-block__task-handle--static {
  cursor: default;
  opacity: 0;
  pointer-events: none;
}

.planner__timeline-pane {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  min-width: 0;
  padding-bottom: 2rem;
}

/* ── Time Gutter + Track ────────────────────────────── */

.planner__timeline-area {
  position: relative;
  display: grid;
  grid-template-columns: 48px 1fr;
  gap: 0;
}

.planner__gutter {
  position: relative;
  border-right: 1px solid rgba(255,255,255,0.04);
}

.planner__gutter-hour {
  position: absolute;
  right: 12px;
  transform: translateY(-50%);
  font-size: 0.6rem;
  font-weight: 600;
  font-family: var(--font-body);
  color: rgba(190, 180, 160, 0.9);
  letter-spacing: 0.02em;
  white-space: nowrap;
  pointer-events: none;
  transition: color var(--dur) var(--ease), opacity var(--dur) var(--ease);
  font-variant-numeric: tabular-nums;
}

.planner__gutter-hour::after {
  content: '';
  position: absolute;
  left: calc(100% + 12px);
  top: 50%;
  width: 12rem;
  height: 1px;
  background: rgba(255,255,255,0.045);
  pointer-events: none;
}

.planner__gutter-hour--past {
  opacity: 0.5;
}

.planner__gutter-now {
  position: absolute;
  right: -5px;
  transform: translateY(-50%);
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow: 0 0 10px rgba(217,153,58,0.5), 0 0 24px rgba(217,153,58,0.2);
  z-index: 5;
  animation: nowDotPulse 3s ease-in-out infinite;
}

/* Global now-line across the timeline track */
.planner__now-line {
  position: absolute;
  left: 48px;
  right: 0;
  height: 2px;
  z-index: 5;
  background: linear-gradient(90deg, var(--accent) 0%, rgba(217,153,58,0.15) 100%);
  pointer-events: none;
}

.planner__now-line::before {
  content: '';
  position: absolute;
  left: -5px;
  top: -4px;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow: 0 0 10px rgba(217,153,58,0.5);
  animation: nowDotPulse 3s ease-in-out infinite;
}

@keyframes nowDotPulse {
  0%, 100% { box-shadow: 0 0 10px rgba(217,153,58,0.4), 0 0 24px rgba(217,153,58,0.15); }
  50%      { box-shadow: 0 0 16px rgba(217,153,58,0.6), 0 0 36px rgba(217,153,58,0.25); }
}

/* Keep legacy keyframe name for reuse */
@keyframes nowLinePulse {
  0%, 100% { opacity: 0.75; }
  50%      { opacity: 1; }
}

