/* ── Planner Block (Calendar Card) ──────────────────── */

.planner-block {
  /* position: absolute set via inline style */
  z-index: 2;
  border-radius: var(--r-sm);
  border: 1px solid rgba(255,255,255,0.06);
  border-left: 3px solid var(--accent);
  background: rgba(255,255,255,0.03);
  backdrop-filter: blur(8px);
  overflow: hidden;
  display: flex;
  flex-direction: column;
  transition:
    border-color var(--dur) var(--ease),
    box-shadow var(--dur) var(--ease),
    background var(--dur) var(--ease),
    opacity var(--dur) var(--ease);
}

.planner-block:hover {
  background: rgba(255,255,255,0.05);
  border-color: rgba(255,255,255,0.1);
  box-shadow: 0 8px 32px rgba(0,0,0,0.2), 0 0 0 1px rgba(255,255,255,0.04);
  z-index: 3;
}

.planner-block--drop-ready {
  transition:
    border-color var(--dur) var(--ease),
    box-shadow var(--dur) var(--ease),
    background var(--dur) var(--ease),
    opacity var(--dur) var(--ease),
    transform var(--dur-fast) var(--ease);
}

.planner-block--drop-target {
  border-color: rgba(217,153,58,0.45);
  background:
    linear-gradient(135deg, rgba(217,153,58,0.14) 0%, rgba(217,153,58,0.05) 100%);
  box-shadow:
    0 14px 40px rgba(217,153,58,0.12),
    0 0 0 1px rgba(217,153,58,0.24);
  transform: scale(1.01);
  z-index: 4;
}

.planner-block--drop-target::after {
  content: "Drop to assign";
  position: absolute;
  top: 0.55rem;
  right: 0.75rem;
  padding: 0.12rem 0.45rem;
  border-radius: var(--r-pill);
  background: rgba(217,153,58,0.16);
  color: var(--accent-bright);
  font-size: 0.58rem;
  font-weight: 800;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  pointer-events: none;
}

.planner-block--current {
  border-left-color: var(--accent);
  border-color: rgba(217,153,58,0.25);
  background:
    linear-gradient(135deg, rgba(217,153,58,0.08) 0%, rgba(217,153,58,0.02) 100%);
  box-shadow:
    0 4px 24px rgba(217,153,58,0.08),
    inset 0 1px 0 rgba(217,153,58,0.1);
}

.planner-block--current:hover {
  box-shadow:
    0 8px 32px rgba(217,153,58,0.12),
    inset 0 1px 0 rgba(217,153,58,0.1);
}

.planner-block--up-next {
  border-left-color: rgba(217,153,58,0.6);
  background: rgba(217,153,58,0.03);
}

.planner-block--past {
  opacity: 0.45;
  border-color: rgba(255,255,255,0.04);
  border-left-color: rgba(255,255,255,0.1);
}

.planner-block--past:hover {
  opacity: 0.65;
}

.planner-block--empty {
  opacity: 0.7;
  border-left-color: var(--text-tertiary);
  background: rgba(255,255,255,0.015);
}

.planner-block__header {
  position: relative;
  z-index: 1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.5rem 0.65rem 0.4rem 0.75rem;
  gap: 0.5rem;
}

.planner-block__info {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  min-width: 0;
  flex: 1;
  overflow: hidden;
}

.planner-block__info-sep {
  color: rgba(255,255,255,0.22);
  font-size: var(--fs-micro);
  flex-shrink: 0;
}

.planner-block__time-badge {
  font-size: var(--fs-micro);
  font-weight: 600;
  color: rgba(190, 180, 160, 0.9);
  letter-spacing: 0.02em;
  white-space: nowrap;
  flex-shrink: 0;
  font-variant-numeric: tabular-nums;
}

.planner-block--current .planner-block__time-badge {
  color: var(--accent-bright);
}

.planner-block__duration {
  font-size: var(--fs-micro);
  font-weight: 600;
  color: rgba(190, 180, 160, 0.8);
  white-space: nowrap;
  flex-shrink: 0;
}

.planner-block__task-count {
  font-size: var(--fs-micro);
  color: rgba(190, 180, 160, 0.8);
  white-space: nowrap;
  flex-shrink: 0;
  font-variant-numeric: tabular-nums;
}

.planner-block__status {
