  font-size: 0.58rem;
  font-weight: 800;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  white-space: nowrap;
  flex-shrink: 0;
}

.planner-block__status--current {
  color: #0f0d08;
  background: var(--accent);
  box-shadow: 0 0 12px rgba(217,153,58,0.3);
}

.planner-block__status--up-next {
  color: var(--accent-bright);
