  now: Date,
): number | null => {
  const start = new Date(startsAt).getTime();
  const end = new Date(endsAt).getTime();
  const nowTime = now.getTime();

  if (nowTime < start || nowTime >= end || end <= start) {
    return null;
  }

  return ((nowTime - start) / (end - start)) * 100;
};

