.today-score-strip__headline { display: flex; align-items: baseline; gap: 0.75rem; flex-wrap: wrap; }
.today-score-strip__label { font-family: var(--font-display); font-size: var(--fs-h3); font-weight: 600; color: var(--text); }
.today-score-strip__pts { font-size: var(--fs-micro); color: var(--text-tertiary); }
.today-score-strip__buckets { display: flex; gap: 0.5rem; flex-wrap: wrap; }
.today-score-strip__nudge { flex-shrink: 0; padding: 0.3rem 0.65rem; border-radius: var(--r-pill); background: var(--accent-soft); border: 1px solid rgba(217,153,58,0.15); }
.today-score-strip__nudge-text { font-size: var(--fs-micro); color: var(--accent-bright); font-weight: 600; white-space: nowrap; }
.today-score-bucket { display: flex; flex-direction: column; align-items: center; gap: 0.2rem; min-width: 3.5rem; }
.today-score-bucket__bar { width: 100%; height: 4px; border-radius: 2px; background: rgba(255,255,255,0.06); overflow: hidden; }
.today-score-bucket__fill { height: 100%; border-radius: 2px; background: var(--accent); transition: width 0.6s var(--ease); }
.today-score-bucket__label { font-size: var(--fs-micro); color: var(--text-tertiary); white-space: nowrap; }
.today-mini-ring { position: relative; display: flex; align-items: center; justify-content: center; }
.today-mini-ring__progress { transition: stroke-dashoffset 0.8s var(--ease); }
.today-mini-ring__value { position: absolute; font-size: 0.85rem; font-weight: 700; color: var(--text); line-height: 1; }
@keyframes scoreBump { 0% { transform: scale(1); } 30% { transform: scale(1.08); } 100% { transform: scale(1); } }
.today-score-strip--bumped .today-mini-ring { animation: scoreBump 0.5s var(--ease); }
.today-score-strip--bumped .today-score-strip__label { animation: scoreBump 0.5s var(--ease); }

/* ── Priority Stack Hero ─────────────────────────────── */

.today-priority-hero {
  border-radius: var(--r);
  border: 1px solid rgba(217,153,58,0.18);
  background:
    radial-gradient(ellipse at 20% 30%, rgba(217,153,58,0.07), transparent 55%),
    linear-gradient(180deg, var(--panel-elevated) 0%, var(--panel) 100%);
  padding: 1.15rem 1.25rem;
  box-shadow: var(--shadow-md), var(--shadow-glow);
  position: relative;
  overflow: hidden;
  border-left: 3px solid var(--accent);
}

.today-priority-hero::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(217,153,58,0.25), transparent);
}

.today-priority-hero__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: 0.85rem;
}

.today-priority-hero__title {
  font-family: var(--font-display);
  font-size: 1.15rem;
  font-weight: 600;
  letter-spacing: -0.01em;
  font-style: italic;
}

.today-priority-hero__subtitle {
  font-size: var(--fs-small);
  color: var(--text-tertiary);
  margin-top: 0.15rem;
}

/* Save Indicator */

.today-save-indicator {
  font-size: var(--fs-micro);
  padding: 0.2rem 0.5rem;
  border-radius: var(--r-pill);
  animation: fadeIn 0.2s ease both;
}

.today-save-indicator--saving {
  color: var(--accent);
  background: var(--accent-soft);
}

.today-save-indicator--saved {
  color: var(--positive);
  background: var(--positive-soft);
}

/* Priority Stack List */

.today-priority-stack {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.today-priority-stack__add {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.35rem;
  padding: 0.55rem 0.75rem;
  margin-top: 0.55rem;
  border-radius: var(--r-sm);
  border: 1px dashed rgba(217,153,58,0.15);
  background: transparent;
  color: var(--text-tertiary);
  font-size: var(--fs-small);
  font-weight: 500;
  transition: all var(--dur) var(--ease);
  width: 100%;
  cursor: pointer;
}

.today-priority-stack__add:hover {
  border-color: rgba(217,153,58,0.3);
  color: var(--text-secondary);
  background: rgba(217,153,58,0.04);
}

.today-priority-stack__add:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* ── Priority Card ───────────────────────────────────── */

.today-priority-card {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.5rem 0.6rem;
  border-radius: var(--r-sm);
  border: 1px solid rgba(217,153,58,0.1);
  background: rgba(255,255,255,0.025);
  transition: border-color var(--dur) var(--ease),
              background var(--dur) var(--ease),
              box-shadow var(--dur) var(--ease),
