payload.aggregated_output:
  .today-score-strip__nudge {
    flex-basis: 100%;
    text-align: center;
  }

  .planner__body {
    grid-template-columns: 1fr;
  }

  .planner__timeline-area {
    grid-template-columns: 44px 1fr;
  }

  .planner__gutter {
    padding-right: 8px;
  }

  .planner__gutter-hour {
    right: 8px;
    font-size: 0.58rem;
  }

  .planner__now-line {
    left: 44px;
  }

  .planner__header {
    flex-direction: column;
    align-items: flex-start;
  }

  .planner-date-nav {
    width: 100%;
    flex-direction: column;
    align-items: flex-start;
    border-radius: var(--r);
    padding: 0.6rem 0.75rem;
    gap: 0.5rem;
  }

  .planner-date-nav__copy {
    width: 100%;
    align-items: flex-start;
    padding-inline: 0;
    text-align: left;
  }

  .planner__hours-card {
    flex-direction: column;
    align-items: stretch;
  }

  .planner__cleanup-banner {
    flex-direction: column;
    align-items: stretch;
  }

  .planner__hours-controls {
    width: 100%;
  }

  .planner__sidebar-pane {
    position: static;
  }

  /* Mobile: unplanned panel becomes fixed bottom bar */
  .unplanned-lane {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 50;
    max-height: 48px;
    padding: 0.6rem 1rem;
    border-radius: var(--r-lg) var(--r-lg) 0 0;
    border: 1px solid var(--border-active);
    border-bottom: none;
    background: var(--panel-elevated);
    box-shadow: 0 -8px 32px rgba(0,0,0,0.3);
    overflow: hidden;
    transition: max-height 0.3s var(--ease);
  }

  .unplanned-lane__header {
    border-bottom: none;
    padding-bottom: 0;
    cursor: pointer;
  }

  .unplanned-lane__list,
  .unplanned-lane__batch,
  .unplanned-lane__helper,
  .unplanned-lane__empty {
    display: none;
  }

  .unplanned-lane--expanded {
    max-height: 65vh;
    overflow-y: auto;
  }

  .unplanned-lane--expanded .unplanned-lane__list,
  .unplanned-lane--expanded .unplanned-lane__batch,
  .unplanned-lane--expanded .unplanned-lane__helper,
  .unplanned-lane--expanded .unplanned-lane__empty {
    display: flex;
  }

  .unplanned-lane--expanded .unplanned-lane__header {
    border-bottom: 1px solid var(--border);
    padding-bottom: 0.35rem;
  }

  .planner__timeline-pane {
    padding-bottom: 64px;
  }

  .today-top-bar {
    flex-direction: column;
    align-items: stretch;
  }

  .mode-toggle {
    align-self: flex-start;
  }

  .recovery-lane__header {
    flex-direction: column;
  }
}

@media (max-width: 640px) {
  .today-health-stats {
    grid-template-columns: 1fr 1fr 1fr;
    gap: 0.35rem;
  }

  .today-hero__buckets {
    display: none;
  }

  .today-score-strip__buckets {
    display: none;
  }

  .today-hero__greeting {
    font-size: 1.3rem;
    white-space: normal;
  }

  .planner__timeline-area {
    grid-template-columns: 40px 1fr;
  }

  .planner__gutter-hour {
    right: 6px;
    font-size: 0.55rem;
  }

  .planner__now-line {
    left: 40px;
  }

  .planner__hours-controls {
    flex-direction: column;
    align-items: stretch;
  }

  .planner__cleanup-actions {
    flex-direction: column;
    align-items: stretch;
  }

  .planner__hours-field {
    min-width: 0;
  }

